import { guidanceSafetyDisclaimer } from "@/lib/guidance-rules";

export default function GuidanceNote() {
  return (
    <div
      style={{
        marginTop: 32,
        padding: "20px 24px",
        background: "rgba(255,255,255,0.01)",
        border: "1px solid rgba(255,255,255,0.04)",
        borderRadius: 12,
        display: "grid",
        gap: 8,
      }}
    >
      <p
        style={{
          margin: 0,
          fontSize: 10,
          letterSpacing: "0.2em",
          textTransform: "uppercase",
          color: "#52525b",
        }}
      >
        A grounded read
      </p>
      <p
        style={{
          margin: 0,
          fontSize: 13,
          lineHeight: 1.6,
          color: "#71717a",
        }}
      >
        {guidanceSafetyDisclaimer}
      </p>
    </div>
  );
}

