import { guidancePhrasing } from "@/lib/guidance-rules";

export default function PerspectiveNote() {
  return (
    <div
      style={{
        padding: 24,
        border: "1px solid rgba(255,255,255,0.06)",
        borderRadius: 16,
        background: "rgba(255,255,255,0.02)",
        display: "grid",
        gap: 18,
      }}
    >
      <div style={{ display: "grid", gap: 8 }}>
        <p
          style={{
            margin: 0,
            fontSize: 10,
            color: "#71717a",
            textTransform: "uppercase",
            letterSpacing: "0.2em",
          }}
        >
          Another side of this
        </p>
        <p
          style={{
            margin: 0,
            fontSize: 14,
            lineHeight: 1.7,
            color: "#a1a1aa",
            maxWidth: 560,
          }}
        >
          People can see the same moment in very different ways. A bit more space
          or clarity may shift what happens next.
        </p>
      </div>

      <div style={{ display: "grid", gap: 12 }}>
        {guidancePhrasing.otherSideGuidance.map((note, i) => (
          <div
            key={i}
            style={{
              display: "grid",
              gridTemplateColumns: "24px 1fr",
              gap: 10,
              alignItems: "start",
              padding: "14px 14px 16px",
              borderRadius: 12,
              background: "rgba(255,255,255,0.03)",
              border: "1px solid rgba(255,255,255,0.05)",
            }}
          >
            <span style={{ fontSize: 11, color: "#52525b", paddingTop: 3 }}>
              0{i + 1}
            </span>
            <p
              style={{
                margin: 0,
                fontSize: 13,
                color: "#d4d4d8",
                lineHeight: 1.7,
              }}
            >
              {note}
            </p>
          </div>
        ))}
      </div>

      <div
        style={{
          padding: "16px 16px 18px",
          borderRadius: 12,
          background: "rgba(255,255,255,0.03)",
          border: "1px solid rgba(255,255,255,0.05)",
          display: "grid",
          gap: 8,
        }}
      >
        <p style={{ margin: 0, fontSize: 13, color: "#f4f4f5", fontWeight: 500 }}>
          If more than one person’s involved
        </p>
        <p style={{ margin: 0, fontSize: 13, color: "#a1a1aa", lineHeight: 1.7 }}>
          Start small and keep it easy to hear. In a group, a calm opening helps
          each person respond without feeling pushed to a side.
        </p>
      </div>
    </div>
  );
}

