import { guidancePhrasing } from "@/lib/guidance-rules";

export default function PhrasingSuggestions() {
  return (
    <div
      style={{
        padding: 24,
        border: "1px solid rgba(255,255,255,0.06)",
        borderRadius: 16,
        background: "rgba(255,255,255,0.02)",
        display: "grid",
        gap: 18,
      }}
    >
      <div style={{ display: "grid", gap: 8 }}>
        <p
          style={{
            margin: 0,
            fontSize: 10,
            color: "#71717a",
            textTransform: "uppercase",
            letterSpacing: "0.2em",
          }}
        >
          A steadier start
        </p>
        <p
          style={{
            margin: 0,
            fontSize: 14,
            lineHeight: 1.7,
            color: "#a1a1aa",
            maxWidth: 560,
          }}
        >
          Small shifts in wording can help people stay open when a topic feels
          charged.
        </p>
      </div>

      <div style={{ display: "grid", gap: 16 }}>
        {guidancePhrasing.phrasingSuggestions.map((item, i) => (
          <div
            key={i}
            style={{
              display: "grid",
              gap: 8,
              padding: "16px 16px 18px",
              borderRadius: 12,
              background: "rgba(255,255,255,0.03)",
              border: "1px solid rgba(255,255,255,0.05)",
            }}
          >
            <p
              style={{
                margin: 0,
                fontSize: 10,
                color: "#71717a",
                textTransform: "uppercase",
                letterSpacing: "0.12em",
              }}
            >
              Instead of
            </p>
            <p
              style={{
                margin: 0,
                fontSize: 13,
                color: "#52525b",
                textDecoration: "line-through",
                opacity: 0.9,
                lineHeight: 1.6,
              }}
            >
              {item.original}
            </p>
            <p
              style={{
                margin: 0,
                fontSize: 10,
                color: "#71717a",
                textTransform: "uppercase",
                letterSpacing: "0.12em",
                paddingTop: 2,
              }}
            >
              Try
            </p>
            <p style={{ margin: 0, fontSize: 14, color: "#f4f4f5", lineHeight: 1.7 }}>
              {item.better}
            </p>
          </div>
        ))}
      </div>

      <p style={{ margin: 0, fontSize: 13, color: "#71717a", lineHeight: 1.7 }}>
        The goal isn’t just to be careful. It’s to make what matters easier to
        hear.
      </p>
    </div>
  );
}

